import { PlaceHolderImages } from '@/lib/placeholder-images';

export type PerformanceTier = 'Contender' | 'Epic' | 'Elite' | 'Ultimate' | 'Legendary' | 'S-Tier';

export interface PerformanceStats {
 ihi: number;      // Power, Vitality, Energy
 wehi: number;     // Awe, Impact, Fear
 wana: number;     // Aura, Authority, Energy
 precision: number; // Technicality, Sync
}

export interface LegacyPerformance {
 id: string;
 name: string;
 year: string;
 location: string;
 image: string;
 videoUrl?: string; 
 audioUrl?: string; 
 isWinner?: boolean;
 tier: PerformanceTier;
 stats: PerformanceStats;
 notableItems: string[];
 itemStats: Record<string, number>;
}

export const KAPA_HAKA_ITEMS = [
 'Whakaeke',
 'Mōteatea',
 'Poi',
 'Waiata-ā-ringa',
 'Haka',
 'Whakawātea'
] as const;

export type KapaHakaItem = typeof KAPA_HAKA_ITEMS[number];

// Stats Engine: Calculates achievement-driven ratings
const calculateStats = (
  base: number, 
  placements: Partial<Record<KapaHakaItem | 'Overall' | 'Reo' | 'Composition', number>>
): { stats: PerformanceStats, itemStats: Record<string, number> } => {
  const itemStats: Record<string, number> = {
    'Whakaeke': base,
    'Mōteatea': base,
    'Poi': base,
    'Waiata-ā-ringa': base,
    'Haka': base,
    'Whakawātea': base
  };

  // Map placements to specific scores
  Object.entries(placements).forEach(([key, rank]) => {
    let score = base + 5;
    if (rank === 1) score = 98;
    if (rank === 2) score = 94;
    if (rank === 3) score = 90;
    
    if (itemStats[key] !== undefined) {
      itemStats[key] = score;
    }
  });

  const avgItem = Object.values(itemStats).reduce((a, b) => a + b, 0) / 6;

  return {
    stats: {
      ihi: Math.min(100, Math.floor(avgItem + (placements.Haka === 1 ? 5 : 0))),
      wehi: Math.min(100, Math.floor(avgItem + (placements.Overall === 1 ? 5 : 0))),
      wana: Math.min(100, Math.floor(avgItem + (placements.Composition === 1 ? 3 : 0))),
      precision: Math.min(100, Math.floor(avgItem + (placements.Poi === 1 ? 5 : 0)))
    },
    itemStats
  };
};

